const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const basePremiumOf = (item: Item): number => {
  if (item.type === "sword") return 100;
  if (item.type === "amulet") return 60;
  return 0;
};

const itemPremiumOf = (item: Item): number => {
  const base = basePremiumOf(item);
  return base * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
};

const quotePremium = (step: Step): number => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremiumOf(item), 0);
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};

